  1	import * as React from 'react';
  2	import {
  3	  FormGroup,
  4	  FormHelperText,
  5	  HelperText,
  6	  HelperTextItem,
  7	  TextInput,
  8	  TextInputTypes,
  9	  ValidatedOptions,
 10	} from '@patternfly/react-core';
 11	import { useFormikContext } from 'formik';
 12	import * as _ from 'lodash';
 13	import { useTranslation } from 'react-i18next';
 14	import { STATUS_KEY_NAME_ERROR } from '../const';
 15	import { NameErrorStatus, PipelineBuilderFormikValues } from '../types';
 16	import { nameValidationSchema } from '../validation-utils';
 17	import { ExclamationCircleIcon } from '@patternfly/react-icons';
 18	
 19	type TaskSidebarNameProps = {
 20	  name: string;
 21	  onChange: (newName: string) => void;
 22	  taskName: string;
 23	};
 24	
 25	const TaskSidebarName: React.FC<TaskSidebarNameProps> = (props) => {
 26	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 27	  const { name, onChange, taskName } = props;
 28	  const { setStatus, status, values } =
 29	    useFormikContext<PipelineBuilderFormikValues>();
 30	  const {
 31	    formData: { tasks, finallyTasks },
 32	  } = values;
 33	  const initialName: string = _.get(values, name, taskName);
 34	  const statusPath: string[] = [STATUS_KEY_NAME_ERROR, name];
 35	  const { nameError, errorMessage }: NameErrorStatus = _.get(
 36	    status,
 37	    statusPath,
 38	    {},
 39	  );
 40	  const [interimName, setInterimName] = React.useState(
 41	    nameError ?? initialName,
 42	  );
 43	  const [validating, setValidating] = React.useState(null);
 44	  const isValid = !errorMessage;
 45	  const reservedNames: string[] = [...tasks, ...finallyTasks]
 46	    .map(({ name: usedName }) => usedName)
 47	    .filter((usedName) => usedName !== initialName);
 48	
 49	  const saveErrorState = (value: string, message: string) => {
 50	    setStatus({
 51	      ...status,
 52	      [STATUS_KEY_NAME_ERROR]: {
 53	        ...(status?.[STATUS_KEY_NAME_ERROR] || {}),
 54	        // `name` stored as a path string intentionally
 55	        [name]: {
 56	          nameError: value,
 57	          errorMessage: message,
 58	        },
 59	      },
 60	    });
 61	  };
 62	  const clearErrorState = () => {
 63	    setStatus({
 64	      ...status,
 65	      [STATUS_KEY_NAME_ERROR]: _.omit(status?.[STATUS_KEY_NAME_ERROR], name),
 66	    });
 67	  };
 68	
 69	  return (
 70	    <FormGroup fieldId="task-name" label={t('Display name')} isRequired>
 71	      <TextInput
 72	        data-test={`task-name ${interimName}`}
 73	        id="task-name"
 74	        validated={isValid ? ValidatedOptions.default : ValidatedOptions.error}
 75	        isRequired
 76	        onChange={(_event, value) => {
 77	          setInterimName(value);
 78	
 79	          if (reservedNames.includes(value)) {
 80	            saveErrorState(value, t('This name is already in use.'));
 81	            return;
 82	          }
 83	
 84	          setValidating(true);
 85	          nameValidationSchema(t, 63)
 86	            .validate(value)
 87	            .then(() => {
 88	              clearErrorState();
 89	              setValidating(false);
 90	            })
 91	            .catch((err) => {
 92	              saveErrorState(value, err?.message || t('Required'));
 93	              setValidating(false);
 94	            });
 95	        }}
 96	        onBlur={() => {
 97	          if (!validating && isValid) {
 98	            onChange(interimName);
 99	          }
100	        }}
101	        placeholder={taskName}
102	        type={TextInputTypes.text}
103	        value={interimName}
104	      />
105	      {!isValid && (
106	        <FormHelperText>
107	          <HelperText>
108	            <HelperTextItem
109	              icon={<ExclamationCircleIcon />}
110	              variant={ValidatedOptions.error}
111	            >
112	              {errorMessage}
113	            </HelperTextItem>
114	          </HelperText>
115	        </FormHelperText>
116	      )}
117	    </FormGroup>
118	  );
119	};
120	
121	export default TaskSidebarName;

